const f=$input.first().json;
const sl=f['Source Language']||'fr';
const tl=f['Target Language']||'en-US';
return [{json:{
  course_id:f['Source Course ID'], target_course_id:f['Target Course ID'],
  source_language:sl, target_language:tl, direction:sl+'>'+tl.split('-')[0],
  email:f['Email'],
  enabled_modules:{
    localize_html:  !!(Array.isArray(f['Localiser le cours (HTML)']) ? f['Localiser le cours (HTML)'].length : f['Localiser le cours (HTML)']),

    audit_only:     !!(Array.isArray(f['Audit du contenu (A1)']) ? f['Audit du contenu (A1)'].length : f['Audit du contenu (A1)']),

    qa_check:       !!(Array.isArray(f['Quality Check /100']) ? f['Quality Check /100'].length : f['Quality Check /100']),

    score_loc:      !!(Array.isArray(f['Score de localisabilité']) ? f['Score de localisabilité'].length : f['Score de localisabilité']),

  },
  score_target:90, started_at:new Date().toISOString()
}}];

const html=$('Call HTML Extraction').first().json.html||'';
const urlRx=/(?:src|href)="([^"#][^"]*)"/g;
const semRx=/data-claire-semantic="([^"]+)"/g;
const urls=[]; let m;
while((m=urlRx.exec(html))!==null) urls.push(m[1]);
const claire=[]; let s;
while((s=semRx.exec(html))!==null) claire.push(s[1]);
return [{json:{type:'fingerprint',urls:[...new Set(urls)],
  claire_semantics:[...new Set(claire)],
  code_blocks_count:(html.match(/<pre[^>]*>/gi)||[]).length,
  raw_html:html}}];

const a1s=$input.all();
const domains=a1s.map(i=>i.json.agent_output?.detected_domain).filter(Boolean);
const cnt={}; domains.forEach(d=>cnt[d]=(cnt[d]||0)+1);
const det=Object.entries(cnt).sort((a,b)=>b[1]-a[1])[0]?.[0]||'Tech';
return [{json:{detected_domain:det,a1_outputs:a1s.map(i=>i.json.agent_output).filter(Boolean),
  course_id:a1s[0]?.json.course_id, target_course_id:a1s[0]?.json.target_course_id||'',
  source_language:a1s[0]?.json.source_language||'fr',
  target_language:a1s[0]?.json.target_language||'en-US', score_target:90}}];

const a5=$input.first().json.agent_output||{};
const iter=($input.first().json.iteration||1);
const score=a5.score_total||0;
const pass=score>=90; const maxed=iter>=3;
return [{json:{...$input.first().json, iteration:iter, score_total:score,
  qa_status:pass?'PASS':(maxed?'ESCALATE':'REVISE'),
  failing_segments:pass?[]:(a5.critical_blockers||[]),
  previous_qa_report:a5, a5_qa_report:a5}}];

const a5=$input.first().json.agent_output||{};
const iter=2;
const score=a5.score_total||0; const pass=score>=90;
return [{json:{...$input.first().json, iteration:iter, score_total:score,
  qa_status:pass?'PASS':'REVISE',
  failing_segments:pass?[]:(a5.critical_blockers||[]),
  previous_qa_report:a5, a5_qa_report:a5}}];

const chunks=$input.all();
const translated=chunks.map(c=>({
  chapter_index:c.json.chapter_index, chunk_index:c.json.chunk_index,
  translated_html:c.json.agent_output?.revised_content||c.json.agent_output?.adapted_content||'',
  type:'chunk', a4_swap_log:c.json.agent_output?.swap_log||[],
  a6_issue_log:c.json.agent_output?.issue_log||[],
  naturalness_score:c.json.agent_output?.naturalness_score||null,
  course_id:chunks[0].json.course_id, target_course_id:chunks[0].json.target_course_id||'',
  source_language:chunks[0].json.source_language, target_language:chunks[0].json.target_language,
  score_total:null, enabled_modules:chunks[0].json.enabled_modules||{}
}));
return translated.map(t=>({json:t}));

const a1 = $('Call A1').all().map(i=>i.json);
const p  = $('Init Params').first().json;
return [{json:{
  status:'AUDIT_COMPLETE', mode:'audit_only',
  course_id:p.course_id, direction:p.direction,
  completed_at:new Date().toISOString(),
  chunks_audited:a1.length,
  a1_results:a1,
  summary:`A1 audit complete — ${a1.length} chunk(s) analysed`
}}];

const a1 = $('Call A1').all().map(i => i.json);
const p  = $('Init Params').first().json;

const scored = a1.filter(r => r.agent_output && r.agent_output.localizability_score != null);
const avg = scored.length
  ? Math.round(scored.reduce((s,r) => s + r.agent_output.localizability_score, 0) / scored.length)
  : 0;

const allBlockers = a1.flatMap(r => (r.agent_output||{}).blockers || []);
const allFlags    = a1.flatMap(r => (r.agent_output||{}).cultural_flags || []);
const domains     = [...new Set(a1.map(r => (r.agent_output||{}).detected_domain).filter(Boolean))];

return [{json:{
  status: 'SCORE_COMPLETE',
  mode: 'score_loc',
  course_id: p.course_id,
  direction: p.direction,
  completed_at: new Date().toISOString(),
  localizability_score: avg,
  chunks_scored: scored.length,
  blockers_count: allBlockers.length,
  blockers: allBlockers,
  cultural_flags_count: allFlags.length,
  detected_domains: domains,
  a1_results: a1
}}];

const a5 = $('Call A5 iter3').all().map(i => i.json);
const p  = $('Init Params').first().json;

const scored = a5.filter(r => r.agent_output && r.agent_output.score != null);
const avg = scored.length
  ? Math.round(scored.reduce((s,r) => s + r.agent_output.score, 0) / scored.length)
  : 0;
const pass = avg >= 90;

const allFailing = a5.flatMap(r => (r.agent_output||{}).critical_blockers || []);
const allWarnings = a5.flatMap(r => (r.agent_output||{}).warnings || []);

return [{json:{
  status: 'QA_COMPLETE',
  mode: 'qa_check',
  course_id: p.course_id,
  direction: p.direction,
  completed_at: new Date().toISOString(),
  qa_score: avg,
  pass,
  chunks_qa: scored.length,
  failing_segments: allFailing,
  failing_count: allFailing.length,
  warnings: allWarnings,
  warnings_count: allWarnings.length,
  a5_results: a5
}}];

const html     = $('Call HTML Extraction').first().json.html || '';
const params   = $('Init Params').first().json;
const fp       = $('Extract Fingerprint').first().json;

return [{json: {
  html:              html,
  course_id:         params.course_id,
  target_course_id:  params.target_course_id,
  source_language:   params.source_language,
  target_language:   params.target_language,
  enabled_modules:   params.enabled_modules,
  fingerprint: {
    urls:              fp.urls,
    claire_semantics:  fp.claire_semantics,
    code_blocks_count: fp.code_blocks_count
  }
}}];

const d   = $input.first().json;
const ip  = $('Init Params').first().json;

const scoreColor = s => s >= 80 ? '#2e7d32' : s >= 60 ? '#e65100' : '#c62828';
const badge = (s,max) => {
  const pct = Math.round((s/max)*100);
  const c = scoreColor(pct);
  return `<span style="background:${c};color:#fff;padding:2px 8px;border-radius:10px;font-weight:bold">${s}/${max}</span>`;
};

let body = `
<div style="font-family:Arial,sans-serif;max-width:800px;margin:0 auto;color:#212121">
<h1 style="border-bottom:3px solid #1565c0;padding-bottom:8px">
  🔍 Audit Report — Course ${d.course_id}
</h1>
<table style="width:100%;border-collapse:collapse;margin-bottom:24px">
  <tr><td style="padding:6px;font-weight:bold;width:160px">Direction</td><td>${d.direction||'fr→en'}</td></tr>
  <tr style="background:#f5f5f5"><td style="padding:6px;font-weight:bold">Date</td><td>${(d.completed_at||'').substring(0,10)}</td></tr>
  <tr><td style="padding:6px;font-weight:bold">Chunks analysed</td><td>${d.chunks_audited||0}</td></tr>
</table>`;

(d.a1_results||[]).forEach((r,i) => {
  const ao = r.agent_output || {};
  const score = ao.localizability_score ?? null;
  const pillar = ao.pillar_scores || {};
  const penalties = ao.penalties || [];
  const flags = ao.cultural_flags || [];
  const blockers = ao.blockers || [];
  const media = ao.media_inventory || [];
  const terms = ao.proposed_terminology || [];

  body += `<h2 style="background:#1565c0;color:#fff;padding:10px 16px;border-radius:6px;margin-top:32px">
    Chapter ${r.chapter_index} — Chunk ${r.chunk_index}
    ${score !== null ? ' &nbsp; ' + badge(score,100) : '<span style="color:#fff;opacity:.7"> (no result)</span>'}
  </h2>`;

  if (ao.detected_domain) body += `<p><strong>Domain detected:</strong> ${ao.detected_domain} &nbsp; <strong>Source:</strong> ${ao.source_language||'?'} → <strong>Target:</strong> ${ao.target_language||'?'}</p>`;

  // Pillar scores table
  if (Object.keys(pillar).length > 0) {
    body += `<h3>📊 Pillar Scores</h3><table style="width:100%;border-collapse:collapse;margin-bottom:16px">`;
    body += `<tr style="background:#e3f2fd"><th style="padding:6px;text-align:left">Pillar</th><th style="padding:6px;text-align:right">Score</th></tr>`;
    Object.entries(pillar).forEach(([k,v],idx) => {
      const bg = idx%2===0 ? '#fff' : '#f9f9f9';
      body += `<tr style="background:${bg}"><td style="padding:6px">${k.replace(/_/g,' ')}</td><td style="padding:6px;text-align:right;font-weight:bold">${v}</td></tr>`;
    });
    body += `</table>`;
  }

  // Blockers
  if (blockers.length > 0) {
    body += `<h3 style="color:#c62828">🚫 Blockers</h3><ul>`;
    blockers.forEach(b => body += `<li style="color:#c62828;margin-bottom:4px">${typeof b==='string'?b:JSON.stringify(b)}</li>`);
    body += `</ul>`;
  }

  // Penalties
  if (penalties.length > 0) {
    body += `<h3 style="color:#e65100">⚠️ Penalties</h3><ul>`;
    penalties.forEach(p => body += `<li><strong>-${p.points||0}pts</strong> ${p.reason||''} — <em>${p.evidence||''}</em></li>`);
    body += `</ul>`;
  }

  // Cultural flags
  if (flags.length > 0) {
    body += `<h3>🌍 Cultural Flags (${flags.length})</h3><table style="width:100%;border-collapse:collapse;margin-bottom:16px">`;
    body += `<tr style="background:#e8f5e9"><th style="padding:6px;text-align:left">Category</th><th style="padding:6px;text-align:left">Source term</th><th style="padding:6px;text-align:left">Proposed swap</th><th style="padding:6px">Effort</th><th style="padding:6px">Blocker</th></tr>`;
    flags.forEach((f,idx) => {
      const bg = idx%2===0 ? '#fff' : '#f9f9f9';
      body += `<tr style="background:${bg}">
        <td style="padding:6px">${f.category||''}</td>
        <td style="padding:6px"><strong>${f.source_term||''}</strong></td>
        <td style="padding:6px">${f.proposed_swap||''}</td>
        <td style="padding:6px;text-align:center">${f.effort||''}</td>
        <td style="padding:6px;text-align:center">${f.blocker?'🔴':'⚪'}</td>
      </tr>`;
    });
    body += `</table>`;
  }

  // Media inventory
  if (media.length > 0) {
    body += `<h3>🎬 Media & Resources (${media.length})</h3><ul>`;
    media.forEach(m => body += `<li><strong>[${m.type||'?'}]</strong> <a href="${m.url||''}">${m.url||''}</a> — risk: <em>${m.risk||'?'}</em>${m.proposed_alternative?' → '+m.proposed_alternative:''}</li>`);
    body += `</ul>`;
  }

  // Proposed terminology
  if (terms.length > 0) {
    body += `<h3>📖 Proposed Terminology (${terms.length})</h3><table style="width:100%;border-collapse:collapse">`;
    body += `<tr style="background:#f3e5f5"><th style="padding:6px;text-align:left">Source</th><th style="padding:6px;text-align:left">Target</th><th style="padding:6px;text-align:left">Category</th></tr>`;
    terms.forEach((t,idx) => {
      const bg = idx%2===0 ? '#fff' : '#f9f9f9';
      body += `<tr style="background:${bg}"><td style="padding:6px">${t.source_term||''}</td><td style="padding:6px"><strong>${t.proposed_target||''}</strong></td><td style="padding:6px">${t.category||''}</td></tr>`;
    });
    body += `</table>`;
  }

  if (r.status === 'error' || !ao.localizability_score) {
    body += `<p style="color:#888;font-style:italic">⚠️ No A1 output for this chunk.</p>`;
  }
});

body += `<hr style="margin-top:40px;border-color:#ddd">
<p style="color:#888;font-size:12px">Generated by CLS v3 — ${d.completed_at||''}</p>
</div>`;

return [{json:{
  html: body,
  subject: '[CLS] Audit — ' + d.course_id + ' (' + (d.direction||'') + ')',
  email: ip.email,
  course_id: d.course_id
}}];

const d  = $input.first().json;
const ip = $('Init Params').first().json;

const scoreColor = s => s >= 80 ? '#2e7d32' : s >= 60 ? '#e65100' : '#c62828';
const badge = s => {
  const c = scoreColor(s);
  return `<span style="background:${c};color:#fff;padding:3px 12px;border-radius:12px;font-size:1.1em;font-weight:bold">${s}/100</span>`;
};

const verdict = d.localizability_score >= 80
  ? '<span style="color:#2e7d32;font-weight:bold">✅ GO — Localization recommended</span>'
  : d.localizability_score >= 60
  ? '<span style="color:#e65100;font-weight:bold">⚠️ CONDITIONAL GO — Review blockers first</span>'
  : '<span style="color:#c62828;font-weight:bold">🚫 NO-GO — Major rework required</span>';

let body = `
<div style="font-family:Arial,sans-serif;max-width:800px;margin:0 auto;color:#212121">
<h1 style="border-bottom:3px solid #1565c0;padding-bottom:8px">
  📊 Localizability Score — Course ${d.course_id}
</h1>
<table style="width:100%;border-collapse:collapse;margin-bottom:24px">
  <tr><td style="padding:6px;font-weight:bold;width:160px">Direction</td><td>${d.direction||''}</td></tr>
  <tr style="background:#f5f5f5"><td style="padding:6px;font-weight:bold">Date</td><td>${(d.completed_at||'').substring(0,10)}</td></tr>
  <tr><td style="padding:6px;font-weight:bold">Domains detected</td><td>${(d.detected_domains||[]).join(', ')||'—'}</td></tr>
  <tr style="background:#f5f5f5"><td style="padding:6px;font-weight:bold">Chunks scored</td><td>${d.chunks_scored||0}</td></tr>
</table>

<div style="text-align:center;padding:24px;background:#f8f9fa;border-radius:8px;margin-bottom:24px">
  <div style="font-size:0.9em;color:#666;margin-bottom:8px">GLOBAL LOCALIZABILITY SCORE</div>
  <div style="font-size:2.5em;margin-bottom:12px">${badge(d.localizability_score||0)}</div>
  <div>${verdict}</div>
</div>`;

// Score par chunk
if ((d.a1_results||[]).length > 0) {
  body += `<h2>Score by Chapter</h2>
<table style="width:100%;border-collapse:collapse;margin-bottom:24px">
<tr style="background:#e3f2fd"><th style="padding:8px;text-align:left">Chapter</th><th style="padding:8px;text-align:left">Domain</th><th style="padding:8px;text-align:center">Score</th><th style="padding:8px;text-align:left">Top flag</th></tr>`;
  (d.a1_results||[]).forEach((r,i) => {
    const ao = r.agent_output || {};
    const s = ao.localizability_score ?? null;
    const bg = i%2===0?'#fff':'#f9f9f9';
    const topFlag = (ao.cultural_flags||[])[0];
    body += `<tr style="background:${bg}">
      <td style="padding:8px">Ch.${r.chapter_index||0} — Chunk ${r.chunk_index||1}</td>
      <td style="padding:8px">${ao.detected_domain||'—'}</td>
      <td style="padding:8px;text-align:center">${s !== null ? badge(s) : '—'}</td>
      <td style="padding:8px;font-size:0.9em">${topFlag ? topFlag.source_term+' → '+topFlag.proposed_swap : '—'}</td>
    </tr>`;
  });
  body += `</table>`;
}

// Blockers
if ((d.blockers||[]).length > 0) {
  body += `<h2 style="color:#c62828">🚫 Blockers (${d.blockers_count})</h2><ul>`;
  (d.blockers||[]).forEach(b => body += `<li style="color:#c62828;margin-bottom:4px">${typeof b==='string'?b:JSON.stringify(b)}</li>`);
  body += `</ul>`;
} else {
  body += `<p style="color:#2e7d32">✅ No blockers detected.</p>`;
}

body += `<hr style="margin-top:40px;border-color:#ddd">
<p style="color:#888;font-size:12px">Generated by CLS v3 — ${d.completed_at||''}</p>
</div>`;

return [{json:{
  html: body,
  subject: `[CLS] Score — ${d.course_id} — ${d.localizability_score||0}/100 (${d.direction||''})`,
  email: ip.email,
  course_id: d.course_id,
  score: d.localizability_score||0
}}];

const d  = $input.first().json;
const ip = $('Init Params').first().json;

const scoreColor = s => s >= 90 ? '#2e7d32' : s >= 75 ? '#e65100' : '#c62828';
const badge = s => {
  const c = scoreColor(s);
  return `<span style="background:${c};color:#fff;padding:3px 12px;border-radius:12px;font-size:1.1em;font-weight:bold">${s}/100</span>`;
};

const verdict = d.pass
  ? '<span style="color:#2e7d32;font-weight:bold">✅ PASS — Ready for delivery</span>'
  : '<span style="color:#c62828;font-weight:bold">❌ FAIL — Failing segments require rework</span>';

let body = `
<div style="font-family:Arial,sans-serif;max-width:800px;margin:0 auto;color:#212121">
<h1 style="border-bottom:3px solid #1565c0;padding-bottom:8px">
  🔎 Quality Check — Course ${d.course_id}
</h1>
<table style="width:100%;border-collapse:collapse;margin-bottom:24px">
  <tr><td style="padding:6px;font-weight:bold;width:160px">Direction</td><td>${d.direction||''}</td></tr>
  <tr style="background:#f5f5f5"><td style="padding:6px;font-weight:bold">Date</td><td>${(d.completed_at||'').substring(0,10)}</td></tr>
  <tr><td style="padding:6px;font-weight:bold">Chunks evaluated</td><td>${d.chunks_qa||0}</td></tr>
</table>

<div style="text-align:center;padding:24px;background:#f8f9fa;border-radius:8px;margin-bottom:24px">
  <div style="font-size:0.9em;color:#666;margin-bottom:8px">QA SCORE (threshold: 90/100)</div>
  <div style="font-size:2.5em;margin-bottom:12px">${badge(d.qa_score||0)}</div>
  <div>${verdict}</div>
</div>`;

// Score par chunk
if ((d.a5_results||[]).length > 0) {
  body += `<h2>Score by Chapter</h2>
<table style="width:100%;border-collapse:collapse;margin-bottom:24px">
<tr style="background:#e3f2fd"><th style="padding:8px;text-align:left">Chapter</th><th style="padding:8px;text-align:center">Score</th><th style="padding:8px;text-align:center">Status</th><th style="padding:8px">Failing segments</th></tr>`;
  (d.a5_results||[]).forEach((r,i) => {
    const ao = r.agent_output || {};
    const s  = ao.score ?? null;
    const ok = s !== null && s >= 90;
    const bg = i%2===0?'#fff':'#f9f9f9';
    const failing = (ao.critical_blockers||[]).length;
    body += `<tr style="background:${bg}">
      <td style="padding:8px">Ch.${r.chapter_index||0} — Chunk ${r.chunk_index||1}</td>
      <td style="padding:8px;text-align:center">${s !== null ? badge(s) : '—'}</td>
      <td style="padding:8px;text-align:center">${ok ? '✅ PASS' : '❌ FAIL'}</td>
      <td style="padding:8px">${failing > 0 ? `${failing} segment(s)` : '—'}</td>
    </tr>`;
  });
  body += `</table>`;
}

// Failing segments
if ((d.failing_segments||[]).length > 0) {
  body += `<h2 style="color:#c62828">❌ Failing Segments (${d.failing_count})</h2><ul>`;
  (d.failing_segments||[]).forEach(s => {
    const txt = typeof s === 'string' ? s : (s.segment_id ? `[${s.segment_id}] ${s.issue||''} — <em>${s.source||''}</em>` : JSON.stringify(s));
    body += `<li style="margin-bottom:6px">${txt}</li>`;
  });
  body += `</ul>`;
}

// Warnings
if ((d.warnings||[]).length > 0) {
  body += `<h2 style="color:#e65100">⚠️ Warnings (${d.warnings_count})</h2><ul>`;
  (d.warnings||[]).forEach(w => body += `<li style="margin-bottom:4px">${typeof w==='string'?w:JSON.stringify(w)}</li>`);
  body += `</ul>`;
}

body += `<hr style="margin-top:40px;border-color:#ddd">
<p style="color:#888;font-size:12px">Generated by CLS v3 — ${d.completed_at||''}</p>
</div>`;

return [{json:{
  html: body,
  subject: `[CLS] QA — ${d.course_id} — ${d.qa_score||0}/100 ${d.pass ? 'PASS ✅' : 'FAIL ❌'} (${d.direction||''})`,
  email: ip.email,
  course_id: d.course_id,
  score: d.qa_score||0,
  pass: d.pass
}}];

const ip = $('Init Params').first().json;
const reassembler = $('Call Reassembler').first().json;
const html = reassembler.final_html || '';
const course_id = ip.course_id;
return [{json:{
  html: html,
  filename: course_id + '_localized.html',
  email: ip.email,
  course_id: course_id
}}];

const glossary = $('Glossary Load 1 (pre-A1)').first().json;
const chunks = $('Call Pre-Processor').all();
return chunks.map(c => ({
  json: {
    ...c.json,
    common_glossary: glossary.common_glossary || [],
    domain_validated_tm: glossary.domain_validated_tm || [],
    domain_unvalidated_tm: glossary.domain_unvalidated_tm || []
  }
}));

const domain = $('Detect Domain').first().json;
const glossary2 = $('Glossary Load 2 (post-A1)').first().json;
const chunks = $('Merge Glossary into Chunks').all();
return chunks.map(c => ({
  json: {
    ...c.json,
    detected_domain: domain.detected_domain,
    a1_outputs: domain.a1_outputs || [],
    a1_audit: (domain.a1_outputs || []).find(a => a && a.chapter_index === c.json.chapter_index) || {},
    target_course_id: domain.target_course_id || c.json.target_course_id || '',
    score_target: domain.score_target || 90,
    common_glossary: glossary2.common_glossary || c.json.common_glossary || [],
    domain_validated_tm: glossary2.domain_validated_tm || [],
    domain_unvalidated_tm: glossary2.domain_unvalidated_tm || []
  }
}));

const f=$input.first().json;
const sl=f['Source Language']||'fr';
